// ── topk: heap-based k-selection ─────────────────────────────────────────────
//
// Algorithm:
//   1. Collect the first min(k, non-null count) valid indices into out_idx (fill).
//   2. Heapify out_idx[0..filled] as a min-heap (for largest=1) or max-heap (for
//      largest=0), where "root = element that would be replaced first".
//   3. Scan remaining valid indices: if an index beats the root, replace and sift down.
//   4. Insertion-sort out_idx[0..filled] for the output order:
//      largest=1 → descending; largest=0 → ascending; ties: lower index first.
//   5. Return filled count.
//
// Null handling: null elements are skipped (not counted against k).
// NaN handling: NaN participates as the largest valid value (dtypes.md §4.6).
//
// Heap comparison (min-heap semantics: root = "worst to keep"):
//   For largest=1: worst = smallest value (or equal value with higher row index).
//   For largest=0: worst = largest value (or equal value with higher row index).
//
// Output comparison (for final sort):
//   For largest=1: descending by value, ties by ascending row index.
//   For largest=0: ascending by value, ties by ascending row index.

/// Heap `less_than` for f64 min-heap (returns true if `a` should be at root).
#[inline(always)]
unsafe fn topk_heap_lt_f64(a: i32, b: i32, data: *const f64, largest: bool) -> bool {
    let av = *data.add(a as usize);
    let bv = *data.add(b as usize);
    let a_nan = av.is_nan();
    let b_nan = bv.is_nan();

    if largest {
        // Root = worst = smallest value; NaN is largest so NaN never at root.
        // a < b (in heap order) means a is worse: smaller value, or equal + higher idx.
        match (a_nan, b_nan) {
            (true, true) => a > b,    // both NaN: higher index is worse
            (true, false) => false,   // NaN > anything: not worse
            (false, true) => true,    // anything < NaN: worse
            (false, false) => {
                use core::cmp::Ordering::{Equal, Less};
                match av.partial_cmp(&bv).unwrap_or(Equal) {
                    Less => true,
                    Equal => a > b,
                    _ => false,
                }
            }
        }
    } else {
        // Root = worst = largest value; NaN is largest so NaN IS at root worst.
        // a < b (in heap order) means a is worse: larger value, or equal + higher idx.
        match (a_nan, b_nan) {
            (true, true) => a > b,
            (true, false) => true,  // NaN is larger/worse for k-smallest
            (false, true) => false,
            (false, false) => {
                use core::cmp::Ordering::{Equal, Greater};
                match av.partial_cmp(&bv).unwrap_or(Equal) {
                    Greater => true,
                    Equal => a > b,
                    _ => false,
                }
            }
        }
    }
}

/// Heap `less_than` for f32 min-heap.
#[inline(always)]
unsafe fn topk_heap_lt_f32(a: i32, b: i32, data: *const f32, largest: bool) -> bool {
    let av = *data.add(a as usize);
    let bv = *data.add(b as usize);
    let a_nan = av.is_nan();
    let b_nan = bv.is_nan();
    if largest {
        match (a_nan, b_nan) {
            (true, true) => a > b,
            (true, false) => false,
            (false, true) => true,
            (false, false) => {
                use core::cmp::Ordering::{Equal, Less};
                match av.partial_cmp(&bv).unwrap_or(Equal) {
                    Less => true,
                    Equal => a > b,
                    _ => false,
                }
            }
        }
    } else {
        match (a_nan, b_nan) {
            (true, true) => a > b,
            (true, false) => true,
            (false, true) => false,
            (false, false) => {
                use core::cmp::Ordering::{Equal, Greater};
                match av.partial_cmp(&bv).unwrap_or(Equal) {
                    Greater => true,
                    Equal => a > b,
                    _ => false,
                }
            }
        }
    }
}

/// Heap `less_than` for i32 min-heap.
#[inline(always)]
unsafe fn topk_heap_lt_i32(a: i32, b: i32, data: *const i32, largest: bool) -> bool {
    let av = *data.add(a as usize);
    let bv = *data.add(b as usize);
    if largest {
        av < bv || (av == bv && a > b)
    } else {
        av > bv || (av == bv && a > b)
    }
}

