/// Insertion sort `out[0..count]` for the final output. k is small in practice.
#[inline]
unsafe fn topk_insertion_sort<F>(out: *mut i32, count: usize, lt: F)
where
    F: Fn(i32, i32) -> bool,
{
    let mut i = 1usize;
    while i < count {
        let key = *out.add(i);
        let mut j = i;
        while j > 0 && lt(key, *out.add(j - 1)) {
            *out.add(j) = *out.add(j - 1);
            j -= 1;
        }
        *out.add(j) = key;
        i += 1;
    }
}

macro_rules! impl_topk {
    (
        $name:ident, $ty:ty,
        $heap_lt:ident,
        $output_lt:ident
    ) => {
        #[no_mangle]
        pub unsafe extern "C" fn $name(
            data_ptr: *const $ty,
            vp: *const u8,
            k: i32,
            out_idx: *mut i32,
            len: u32,
            largest: i32,
        ) -> i32 {
            let k = k as usize;
            let len = len as usize;
            let largest = largest != 0;

            if k == 0 || len == 0 {
                return 0;
            }

            let mut filled = 0usize; // elements currently in the heap

            for i in 0..len {
                if !is_valid(vp, i) {
                    continue; // skip null rows
                }
                let idx = i as i32;

                if filled < k {
                    // Fill phase: accumulate first k valid indices.
                    *out_idx.add(filled) = idx;
                    filled += 1;
                    // Once we have exactly k elements, build the heap.
                    if filled == k {
                        heap_build(out_idx, filled, |a, b| $heap_lt(a, b, data_ptr, largest));
                    }
                } else {
                    // Replacement phase: compare with root.
                    let root = *out_idx; // root is at index 0
                    if $heap_lt(root, idx, data_ptr, largest) {
                        // root is "worse" than new candidate → replace root.
                        *out_idx = idx;
                        heap_sift_down(out_idx, filled, 0, |a, b| {
                            $heap_lt(a, b, data_ptr, largest)
                        });
                    }
                }
            }

            // Sort the collected indices for the required output order.
            topk_insertion_sort(out_idx, filled, |a, b| $output_lt(a, b, data_ptr, largest));

            filled as i32
        }
    };
}

impl_topk!(topk_f64, f64, topk_heap_lt_f64, topk_output_lt_f64);
impl_topk!(topk_f32, f32, topk_heap_lt_f32, topk_output_lt_f32);
impl_topk!(topk_i32, i32, topk_heap_lt_i32, topk_output_lt_i32);
impl_topk!(topk_u32, u32, topk_heap_lt_u32, topk_output_lt_u32);

